const humanizeAccountOrderStatus = (status?: string | null): string => {
  if (!status) return "Pending";
  return formatOrderStatusLabel(status) || "Pending";
};

const normalizeTrackingStatusToken = (value?: string | null) => {
  const raw = String(value || "").trim().toLowerCase();
  if (!raw) return null;
  return raw.replace(/[\s-]+/g, "_");
};

const formatTrackingDeliveredDate = (value?: string | null) => {
  const date = parseBackendTimestamp(value);
  if (!date) return null;
  return date.toLocaleDateString("en-US", {
    month: "short",
    day: "numeric",
    year: "numeric",
  });
};

const resolveOrderDeliveredAt = (order?: AccountOrderSummary | null): string | null => {
  if (!order || typeof order !== "object") {
    return null;
  }
  const shippingEstimate =
    order.shippingEstimate && typeof order.shippingEstimate === "object"
      ? order.shippingEstimate
      : null;
  const integrations = parseMaybeJson(order.integrationDetails || order.integrations || null) || {};
  const carrierTracking = parseMaybeJson(
    (integrations as any)?.carrierTracking || (integrations as any)?.carrier_tracking || null,
  ) || {};
  const candidates = [
    (order as any).upsDeliveredAt,
    (order as any).ups_delivered_at,
    shippingEstimate?.deliveredAt,
    (shippingEstimate as any)?.delivered_at,
    carrierTracking?.deliveredAt,
    carrierTracking?.delivered_at,
  ];
  for (const candidate of candidates) {
    if (typeof candidate === "string" && candidate.trim().length > 0) {
      return candidate.trim();
    }
  }
  return null;
};

const resolveOrderTrackingStatusRaw = (order?: AccountOrderSummary | null): string | null => {
  if (!order || typeof order !== "object") {
    return null;
  }
  const shippingEstimate =
    order.shippingEstimate && typeof order.shippingEstimate === "object"
      ? order.shippingEstimate
      : null;
  const integrations = parseMaybeJson(order.integrationDetails || order.integrations || null) || {};
  const carrierTracking = parseMaybeJson(
    (integrations as any)?.carrierTracking || (integrations as any)?.carrier_tracking || null,
  ) || {};
  const candidates = [
    (order as any).upsTrackingStatus,
    (order as any).ups_tracking_status,
    shippingEstimate?.status,
    carrierTracking?.trackingStatusRaw,
    carrierTracking?.trackingStatus,
    carrierTracking?.tracking_status,
    carrierTracking?.status,
    carrierTracking?.deliveryStatus,
    carrierTracking?.delivery_status,
  ];
  for (const candidate of candidates) {
    if (typeof candidate === "string" && candidate.trim().length > 0) {
      return candidate.trim();
    }
  }
  return null;
};

const buildOrderTrackingStatusLine = (order?: AccountOrderSummary | null): string | null => {
  const rawStatus = resolveOrderTrackingStatusRaw(order);
  if (!rawStatus) {
    return null;
  }
  const deliveredDateLabel = formatTrackingDeliveredDate(resolveOrderDeliveredAt(order));
  const normalizedStatus = normalizeTrackingStatusToken(rawStatus);
  const label = humanizeAccountOrderStatus(rawStatus);
  if (deliveredDateLabel && normalizedStatus?.includes("delivered")) {
    return `${label} on ${deliveredDateLabel}`;
  }
  return label;
};

const formatPepProPaymentMethodLabel = (value?: string | null): string | null => {
  if (!value) return null;
  const raw = String(value).trim();
  if (!raw) return null;
  const normalized = raw.toLowerCase().replace(/[\s-]+/g, "_");

  if (normalized.includes("zelle")) return "Zelle";
  if (
    normalized === "bacs" ||
    normalized === "bank_transfer" ||
    normalized === "direct_bank_transfer" ||
    normalized.includes("direct_bank_transfer") ||
    normalized.includes("direct_bank") ||
    normalized.includes("bank_transfer") ||
    normalized.includes("banktransfer")
  ) {
    return "Direct Bank Transfer";
  }
  if (normalized.includes("stripe")) return "Card payment";

  return raw;
};

const parseMaybeJson = (value: any) => {
  if (typeof value === "string") {
    try {
      return JSON.parse(value);
    } catch {
      return value;
    }
  }
  return value;
};

const buildTrackingUrl = (tracking: string, carrier?: string | null) => {
  if (!tracking) return null;
  const code = (carrier || "").toLowerCase();
  const encoded = encodeURIComponent(tracking);
  if (code.includes("ups")) return `https://www.ups.com/track?loc=en_US&tracknum=${encoded}`;
  if (code.includes("usps")) return `https://tools.usps.com/go/TrackConfirmAction?tLabels=${encoded}`;
  if (code.includes("fedex")) return `https://www.fedex.com/fedextrack/?trknbr=${encoded}`;
  if (code.includes("dhl")) return `https://www.dhl.com/en/express/tracking.html?AWB=${encoded}`;
  return `https://www.google.com/search?q=${encoded}`;
};

const resolveTrackingNumber = (order: any): string | null => {
  if (!order) return null;

  const orderLabel =
    order?.number ||
    order?.id ||
    order?.wooOrderNumber ||
    order?.orderNumber ||
    "unknown";

  let tracking: string | null = null;

  const direct =
    order?.trackingNumber ||
    order?.tracking_number ||
    order?.tracking ||
    null;
  if (direct) {
    tracking = String(direct);
  }

  if (!tracking) {
    const integrations = parseMaybeJson(order.integrationDetails || order.integrations);
    const shipStation = parseMaybeJson(integrations?.shipStation || integrations?.shipstation);

    const shipStationDirect =
      shipStation?.trackingNumber ||
      shipStation?.tracking_number ||
      shipStation?.tracking ||
      null;
    if (shipStationDirect) {
      tracking = String(shipStationDirect);
    }

    if (!tracking) {
      const shipments =
        shipStation?.shipments ||
        shipStation?.shipment ||
        shipStation?.data?.shipments ||
        [];

      if (Array.isArray(shipments)) {
        const pickTracking = (entry: any) =>
          entry?.trackingNumber || entry?.tracking_number || entry?.tracking || null;
        const nonVoided = shipments.find(
          (entry) => entry && entry.voided === false && pickTracking(entry),
        );
        const anyEntry = shipments.find((entry) => entry && pickTracking(entry));
        const candidate = nonVoided || anyEntry;
        if (candidate) {
          tracking = String(pickTracking(candidate));
        }
      }
    }
  }

  if (tracking) {
    return tracking;
  }

  return null;
};

const resolveSalesOrderStatusSource = (
  order?: AccountOrderSummary | null,
): string | null => {
  if (!order) return null;
  const orderStatus = String(order.status || "").trim();
  const integrations = parseMaybeJson(order.integrationDetails || order.integrations);
  const shipStation = parseMaybeJson(integrations?.shipStation || integrations?.shipstation);
  const carrierTracking = parseMaybeJson(
    integrations?.carrierTracking ||
      integrations?.carrier_tracking ||
      integrations?.trackingDetails ||
      integrations?.tracking_details,
  );
  const shipments =
    shipStation?.shipments || shipStation?.shipment || shipStation?.data?.shipments || [];
  const shipStationStatus =
    shipStation?.status ||
    (Array.isArray(shipments)
      ? (() => {
          const candidate = shipments.find(
            (entry: any) =>
              entry &&
              (entry?.status ||
                entry?.shipmentStatus ||
                entry?.shipment_status ||
                entry?.trackingStatus ||
                entry?.tracking_status ||
                entry?.deliveryStatus ||
                entry?.delivery_status),
          );
          return (
            (candidate as any)?.status ||
            (candidate as any)?.shipmentStatus ||
            (candidate as any)?.shipment_status ||
            (candidate as any)?.trackingStatus ||
            (candidate as any)?.tracking_status ||
            (candidate as any)?.deliveryStatus ||
            (candidate as any)?.delivery_status ||
            null
          );
        })()
      : null);
  const carrierTrackingStatus =
    carrierTracking?.trackingStatus ||
    carrierTracking?.tracking_status ||
    carrierTracking?.status ||
    carrierTracking?.deliveryStatus ||
    carrierTracking?.delivery_status ||
    null;
  const shippingStatus =
    (order.shippingEstimate as any)?.status || carrierTrackingStatus || shipStationStatus;

  if (shouldDisplayShippingStatusForOrder(orderStatus, shippingStatus)) {
    const shippingCandidate = String(shippingStatus || "").trim();
    if (shippingCandidate.length > 0) {
      return shippingCandidate;
    }
  }

  const candidate = orderStatus || shippingStatus || null;
  if (!candidate) return null;
  const str = String(candidate).trim();
  return str.length > 0 ? str : null;
};

const resolveSalesOrderShippingStatus = (
  order?: AccountOrderSummary | null,
): string | null => {
  if (!order) return null;
  const integrations = parseMaybeJson(order.integrationDetails || order.integrations);
  const shipStation = parseMaybeJson(integrations?.shipStation || integrations?.shipstation);
  const carrierTracking = parseMaybeJson(
    integrations?.carrierTracking ||
      integrations?.carrier_tracking ||
      integrations?.trackingDetails ||
      integrations?.tracking_details,
  );
  const shipments =
    shipStation?.shipments || shipStation?.shipment || shipStation?.data?.shipments || [];
  const carrierTrackingStatus =
    carrierTracking?.trackingStatus ||
    carrierTracking?.tracking_status ||
    carrierTracking?.status ||
    carrierTracking?.deliveryStatus ||
    carrierTracking?.delivery_status ||
    null;
  const direct =
    (order.shippingEstimate as any)?.status ||
    carrierTrackingStatus ||
    shipStation?.status ||
    null;
  if (direct) return String(direct).trim() || null;
  if (!Array.isArray(shipments)) return null;
  const candidate = shipments.find(
    (entry: any) =>
      entry &&
      (entry?.status ||
        entry?.shipmentStatus ||
        entry?.shipment_status ||
        entry?.trackingStatus ||
        entry?.tracking_status ||
        entry?.deliveryStatus ||
        entry?.delivery_status),
  );
  const value =
    (candidate as any)?.status ||
    (candidate as any)?.shipmentStatus ||
    (candidate as any)?.shipment_status ||
    (candidate as any)?.trackingStatus ||
    (candidate as any)?.tracking_status ||
    (candidate as any)?.deliveryStatus ||
    (candidate as any)?.delivery_status ||
    null;
  return value ? String(value).trim() || null : null;
};

const getSalesOrderFulfillmentTokens = (
  order?: AccountOrderSummary | null,
): string[] => {
  if (!order) return [];
  return [
    (order as any)?.handDelivery === true ? "hand_delivery" : "",
    (order as any)?.facilityPickup === true ? "facility_pickup" : "",
    (order as any)?.facility_pickup === true ? "facility_pickup" : "",
    (order as any)?.fascility_pickup === true ? "fascility_pickup" : "",
    (order as any)?.fulfillmentMethod,
    (order as any)?.fulfillment_method,
    (order as any)?.shippingService,
    (order as any)?.shipping_service,
    (order as any)?.shippingEstimate?.serviceType,
    (order as any)?.shippingEstimate?.serviceCode,
    (order as any)?.shippingEstimate?.carrierId,
  ]
    .map((value) => String(value || "").trim().toLowerCase())
    .filter(Boolean);
};

const isSalesOrderFacilityPickup = (
  order?: AccountOrderSummary | null,
): boolean => {
  if (!order) return false;
  if (resolveTrackingNumber(order)) return false;
  const shippingAddress =
    (order as any)?.shippingAddress ||
    (order as any)?.shipping ||
    (order as any)?.shipping_address ||
    null;
  const billingAddress =
    (order as any)?.billingAddress ||
    (order as any)?.billing ||
    (order as any)?.billing_address ||
    null;
  const candidates = getSalesOrderFulfillmentTokens(order);
  return candidates.some((value) =>
    value === "facility pickup" ||
    value === "fascility_pickup" ||
    value === "facility_pickup",
  ) || isFacilityPickupAddress(shippingAddress)
    || isFacilityPickupAddress(billingAddress);
};

const isSalesOrderHandDelivered = (
  order?: AccountOrderSummary | null,
): boolean => {
  if (!order) return false;
  if (resolveTrackingNumber(order)) return false;
  if (isSalesOrderFacilityPickup(order)) return false;
  const candidates = getSalesOrderFulfillmentTokens(order);
  return candidates.some((value) =>
    value === "hand delivery" ||
    value === "hand delivered" ||
    value === "hand_delivery" ||
    value === "hand_delivered" ||
    value === "local hand delivery" ||
    value === "local_hand_delivery" ||
    value === "local_delivery" ||
    value === "hand-delivery" ||
    value === "hand-delivered",
  );
};

const describeSalesOrderStatus = (
  order?: AccountOrderSummary | null,
): string => {
  const raw = resolveSalesOrderStatusSource(order);
  const statusRaw = raw ? String(raw) : "";
  const normalized = statusRaw.trim().toLowerCase();
  const normalizedToken = normalized.replace(/[\s-]+/g, "_");
  const shippingStatusRaw = resolveSalesOrderShippingStatus(order);
  const shippingNormalized = shippingStatusRaw
    ? String(shippingStatusRaw).trim().toLowerCase()
    : "";
  if (
    normalized === "trash" ||
    normalized === "canceled" ||
    normalized === "cancelled"
  ) {
    return "Canceled";
  }
  if (normalized === "refunded") {
    return "Refunded";
  }
  if (normalizedToken === "on_hold" || normalizedToken === "onhold") {
    return "On-Hold";
  }

  if (
    shippingNormalized.includes("out_for_delivery") ||
    shippingNormalized.includes("out-for-delivery")
  ) {
    return "Out for Delivery";
  }
  if (
    shippingNormalized.includes("in_transit") ||
    shippingNormalized.includes("in-transit")
  ) {
    return "In transit";
  }
  if (shippingNormalized.includes("delivered")) {
    return "Delivered";
  }
  if (
    shippingNormalized.includes("label_created") ||
    shippingNormalized.includes("awaiting_shipment") ||
    shippingNormalized.includes("awaiting")
  ) {
    return "Label Created";
  }
  if (
    shippingNormalized.includes("exception") ||
    shippingNormalized.includes("delay") ||
    shippingNormalized.includes("held") ||
    shippingNormalized.includes("hold") ||
    shippingNormalized.includes("error")
  ) {
    return "Exception";
  }

  const tracking =
    typeof (order as any)?.trackingNumber === "string"
      ? String((order as any).trackingNumber).trim()
      : "";
  const eta = (order?.shippingEstimate as any)?.estimatedArrivalDate || null;
  const hasEta = typeof eta === "string" && eta.trim().length > 0;

  if (normalized === "shipped") {
    return tracking ? "Shipped" : "Shipped";
  }
  if (
    normalized.includes("out_for_delivery") ||
    normalized.includes("out-for-delivery")
  ) {
    return "Out for Delivery";
  }
  if (
    normalized.includes("in_transit") ||
    normalized.includes("in-transit")
  ) {
    return "In transit";
  }
  if (normalized.includes("delivered")) {
    return "Delivered";
  }
  if (
    normalized.includes("label_created") ||
    normalized.includes("awaiting_shipment") ||
    normalized.includes("awaiting")
  ) {
    return "Label Created";
  }
  if (
    normalized.includes("exception") ||
    normalized.includes("delay") ||
    normalized.includes("held") ||
    normalized.includes("hold") ||
    normalized.includes("error")
  ) {
    return "Exception";
  }

  if (tracking) return "Shipped";
  if (normalized === "processing") {
    return "Processing";
  }
  if (normalized === "completed" || normalized === "complete") {
    return "Shipped";
  }
  if (normalized === "awaiting_shipment" || normalized === "awaiting shipment") {
    return "Label Created";
  }

  if (!raw) return "Pending";
  return humanizeAccountOrderStatus(raw);
};

const VARIATION_CACHE_STORAGE_KEY = "peppro_variation_cache_v2";

const normalizeAddressPart = (value?: string | null) => {
  if (typeof value === "string") {
    const trimmed = value.trim();
    return trimmed.length > 0 ? trimmed : null;
  }
  return null;
};

const hasSavedAddress = (address?: AccountOrderAddress | null) => {
  if (!address) {
    return false;
  }
  return Boolean(
    normalizeAddressPart(address.addressLine1) ||
    normalizeAddressPart(address.city) ||
    normalizeAddressPart(address.state) ||
    normalizeAddressPart(address.postalCode),
  );
};

const sanitizeAccountAddress = (
  address?: AccountOrderAddress | null,
  fallbackName?: string | null,
): AccountOrderAddress | undefined => {
  if (!address && !fallbackName) {
    return undefined;
  }
  return {
    name:
      normalizeAddressPart(address?.name) || normalizeAddressPart(fallbackName),
    company: normalizeAddressPart(address?.company),
    addressLine1: normalizeAddressPart(address?.addressLine1),
    addressLine2: normalizeAddressPart(address?.addressLine2),
    city: normalizeAddressPart(address?.city),
    state: normalizeAddressPart(address?.state),
    postalCode: normalizeAddressPart(address?.postalCode),
    country: normalizeAddressPart(address?.country) || "US",
    phone: normalizeAddressPart(address?.phone),
    email: normalizeAddressPart(address?.email),
  };
};

const normalizeAddressComparisonPart = (value?: string | null) =>
  normalizeAddressPart(value)
    ?.toLowerCase()
    .replace(/[.,]/g, "")
    .replace(/\s+/g, " ")
    .trim() || null;

const isFacilityPickupAddress = (address?: AccountOrderAddress | null) => {
  if (!address) return false;

  const name = normalizeAddressComparisonPart(address.name);
  const line1 = normalizeAddressComparisonPart(address.addressLine1);
  const line2 = normalizeAddressComparisonPart(address.addressLine2);
  const combinedLine = [line1, line2].filter(Boolean).join(" ");
  const city = normalizeAddressComparisonPart(address.city);
  const state = normalizeAddressComparisonPart(address.state);
  const postalCode = normalizeAddressComparisonPart(address.postalCode);

  const matchesName = name === "peppro facility pickup";
  const matchesStreet =
    line1 === "640 s grand ave" || combinedLine.includes("640 s grand ave");
  const matchesUnit =
    line2 === "unit #107" ||
    line2 === "unit 107" ||
    combinedLine.includes("unit #107") ||
    combinedLine.includes("unit 107");
  const matchesLocation =
    city === "santa ana" && state === "ca" && postalCode === "92705";

  return (matchesStreet && matchesUnit && matchesLocation) || (matchesName && matchesLocation);
};

const getInitials = (name?: string | null) => {
  if (!name) return "PP";
  const honorifics = new Set([
    "mr",
    "mrs",
    "ms",
    "miss",
    "mx",
    "dr",
    "doctor",
    "prof",
    "sir",
    "madam",
  ]);
  const suffixes = new Set(["jr", "sr", "ii", "iii", "iv", "v"]);
  const tokens = name
    .split(/\s+/)
    .map((token) => token.replace(/[.,]/g, "").trim())
    .filter(Boolean);
  const filtered = tokens.filter((token, idx) => {
    const lower = token.toLowerCase();
    if (honorifics.has(lower)) return false;
    if (idx === tokens.length - 1 && suffixes.has(lower)) return false;
    return true;
  });
  const parts = filtered.length ? filtered : tokens;
  if (parts.length === 0) return "PP";
  if (parts.length === 1) return parts[0].slice(0, 2).toUpperCase() || "PP";
  const first = parts[0]?.[0] || "";
  const last = parts[parts.length - 1]?.[0] || "";
  return (first + last).toUpperCase() || "PP";
};

const buildShippingAddressFromUserProfile = (
  user?: User | null,
): AccountOrderAddress | undefined => {
  if (!user) {
    return undefined;
  }
  const candidate: AccountOrderAddress = {
    name: user.name || user.npiVerification?.name || null,
    addressLine1: user.officeAddressLine1 || null,
    addressLine2: user.officeAddressLine2 || null,
    city: user.officeCity || null,
    state: user.officeState || null,
    postalCode: user.officePostalCode || null,
    country: "US",
  };
  return hasSavedAddress(candidate)
    ? sanitizeAccountAddress(candidate)
    : undefined;
};

const deriveShippingAddressFromOrders = (
  orders: AccountOrderSummary[],
  fallbackName?: string | null,
): AccountOrderAddress | undefined => {
  if (!orders || orders.length === 0) {
    return undefined;
  }
  for (const order of orders) {
    if (hasSavedAddress(order.shippingAddress)) {
      return sanitizeAccountAddress(order.shippingAddress, fallbackName);
    }
    if (hasSavedAddress(order.billingAddress)) {
      return sanitizeAccountAddress(order.billingAddress, fallbackName);
    }
  }
  return undefined;
};

const WOO_PLACEHOLDER_IMAGE = resolveStaticAssetUrl("/PepPro_icon.png");

const normalizeWooImageUrl = (value?: string | null): string | null => {
  if (typeof value !== "string") {
    return null;
  }
  let candidate = value.trim();
  if (!candidate) {
    return null;
  }
  if (candidate.startsWith("//")) {
    candidate = `https:${candidate}`;
  }
  if (/^http:\/\//i.test(candidate)) {
    candidate = candidate.replace(/^http:\/\//i, "https://");
  }
  try {
    const url = new URL(candidate);
    url.protocol = "https:";
    url.pathname = url.pathname
      .split("/")
      .map((segment) => encodeURIComponent(decodeURIComponent(segment)))
      .join("/");
    return proxifyWooMediaUrl(url.toString());
  } catch (_error) {
    return proxifyWooMediaUrl(candidate);
  }
};

const normalizeProfileAvatarUrl = (value: unknown): string | null => {
  if (typeof value !== "string") {
    return null;
  }
  let candidate = value.trim();
  if (!candidate || candidate === WOO_PLACEHOLDER_IMAGE) {
    return null;
  }
  if (/^(data|blob):/i.test(candidate)) {
    return candidate;
  }
  if (candidate.startsWith("//")) {
    candidate = `https:${candidate}`;
  }
  if (candidate.startsWith("/")) {
    return candidate;
  }
  if (/^https?:\/\//i.test(candidate)) {
    try {
      const parsed = new URL(candidate);
      const shouldUseWooProxy =
        parsed.hostname === "shop.peppro.net" || /\/wp-content\//i.test(parsed.pathname);
      if (shouldUseWooProxy) {
        return normalizeWooImageUrl(candidate);
      }
      parsed.protocol = "https:";
      parsed.pathname = parsed.pathname
        .split("/")
        .map((segment) => encodeURIComponent(decodeURIComponent(segment)))
        .join("/");
      return parsed.toString();
    } catch {
      return candidate;
    }
  }
  try {
    const base =
      typeof window !== "undefined" && window.location?.origin
        ? window.location.origin
        : "https://peppro.net";
    return new URL(candidate, base).toString();
  } catch {
    return candidate;
  }
};

const RESET_PASSWORD_ROUTE = "/reset-password";

const normalizePathname = (pathname?: string | null) => {
  if (!pathname) {
    return "/";
  }
  const trimmed = pathname.replace(/\/+$/, "");
  return trimmed || "/";
};

const isResetPasswordRoute = () =>
  typeof window !== "undefined" &&
  normalizePathname(window.location.pathname) === RESET_PASSWORD_ROUTE;

const readResetTokenFromLocation = () => {
  if (typeof window === "undefined") {
    return null;
  }
  return new URLSearchParams(window.location.search).get("token");
};

const getInitialLandingMode = (): "login" | "signup" | "forgot" | "reset" =>
  isResetPasswordRoute() ? "reset" : "login";

const getInitialResetToken = () =>
  isResetPasswordRoute() ? readResetTokenFromLocation() : null;

const DEFAULT_DELEGATE_SECONDARY_COLOR = '#5fb3f9';

const normalizeDelegateSecondaryColor = (value?: string | null) => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  if (!trimmed) return null;
  const raw = trimmed.startsWith('#') ? trimmed.slice(1) : trimmed;
  if (/^[0-9a-fA-F]{3}$/.test(raw)) {
    return `#${raw.split('').map((char) => `${char}${char}`).join('').toLowerCase()}`;
  }
  if (/^[0-9a-fA-F]{6}$/.test(raw)) {
    return `#${raw.toLowerCase()}`;
  }
  return null;
};

const hexToRgbCss = (hex: string) => {
  const normalized = normalizeDelegateSecondaryColor(hex) || DEFAULT_DELEGATE_SECONDARY_COLOR;
  const raw = normalized.slice(1);
  const r = Number.parseInt(raw.slice(0, 2), 16);
  const g = Number.parseInt(raw.slice(2, 4), 16);
  const b = Number.parseInt(raw.slice(4, 6), 16);
  return `rgb(${r}, ${g}, ${b})`;
};

const hexToRgbaCss = (hex: string, alpha: number) => {
  const normalized = normalizeDelegateSecondaryColor(hex) || DEFAULT_DELEGATE_SECONDARY_COLOR;
  const raw = normalized.slice(1);
  const r = Number.parseInt(raw.slice(0, 2), 16);
  const g = Number.parseInt(raw.slice(2, 4), 16);
  const b = Number.parseInt(raw.slice(4, 6), 16);
  return `rgba(${r}, ${g}, ${b}, ${alpha})`;
};

const coerceNumber = (value: unknown): number | undefined => {
  if (typeof value === "number" && Number.isFinite(value)) {
    return value;
  }
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : undefined;
};

const normalizeIdField = (
  value: unknown,
): string | number | null => {
  if (typeof value === "number" && Number.isFinite(value)) {
    return value;
  }
  if (typeof value === "string") {
    const trimmed = value.trim();
    return trimmed.length > 0 ? trimmed : null;
  }
  return null;
};

const resolveLineImageUrl = (item: any): string | null => {
  const candidates = [
    item?.image,
    item?.imageUrl,
    item?.image_url,
    item?.thumbnail,
    item?.thumb,
  ];
  for (const candidate of candidates) {
    if (typeof candidate === "string" && candidate.trim().length > 0) {
      return candidate.trim();
    }
    if (candidate && typeof candidate === "object") {
      const source =
        candidate.src ||
        candidate.url ||
        candidate.href ||
        candidate.source;
      if (typeof source === "string" && source.trim().length > 0) {
        return source.trim();
      }
    }
  }

  const metadata = Array.isArray(item?.meta_data)
    ? item.meta_data
    : Array.isArray(item?.meta)
      ? item.meta
      : [];
  for (const entry of metadata) {
    const value = entry?.value;
    if (typeof value === "string" && value.trim().length > 0) {
      return value.trim();
    }
    if (value && typeof value === "object") {
      const source =
        value.src || value.url || value.href || value.source;
      if (typeof source === "string" && source.trim().length > 0) {
        return source.trim();
      }
    }
  }
  return null;
};

const toOrderLineItems = (items: any): AccountOrderLineItem[] => {
  if (!Array.isArray(items)) {
    return [];
  }
  return items
    .map((item) => {
      const quantity = coerceNumber(item?.quantity);
      const price = coerceNumber(item?.price);
      const total =
        coerceNumber(item?.total) ??
        (price && quantity ? price * quantity : undefined);
      return {
        id: item?.id ? String(item.id) : undefined,
        name: typeof item?.name === "string" ? item.name : null,
        quantity: quantity ?? null,
        total: total ?? null,
        price: price ?? null,
        sku:
          typeof item?.sku === "string" && item.sku.trim().length > 0
            ? item.sku.trim()
            : null,
        productId: normalizeIdField(
          item?.productId ?? item?.product_id ?? item?.wooProductId,
        ),
        variantId: normalizeIdField(
          item?.variantId ??
            item?.variation_id ??
            item?.wooVariationId,
        ),
        image: resolveLineImageUrl(item),
      };
    })
    .filter((line) => line.name);
};

const resolveOrderItemsSubtotal = (order: any): number => {
  if (!order) return 0;
  const lineItems = Array.isArray(order?.lineItems)
    ? order.lineItems
    : Array.isArray(order?.items)
      ? toOrderLineItems(order.items)
      : [];

  const fromLines = Array.isArray(lineItems)
    ? lineItems.reduce((sum: number, line: any) => {
        const qty = coerceNumber(line?.quantity) ?? 0;
        if (qty <= 0) return sum;
        const lineTotal = coerceNumber(line?.total);
        if (typeof lineTotal === "number" && Number.isFinite(lineTotal) && lineTotal > 0) {
          return sum + lineTotal;
        }
        const unitPrice = coerceNumber(line?.price);
        if (typeof unitPrice === "number" && Number.isFinite(unitPrice) && unitPrice > 0) {
          return sum + unitPrice * qty;
        }
        return sum;
      }, 0)
    : 0;

  if (fromLines > 0) {
    return Math.max(0, fromLines);
  }

  const direct = coerceNumber(
    order?.itemsSubtotal ??
      order?.items_subtotal ??
      order?.itemsTotal ??
      order?.items_total ??
      order?.subtotal,
  );
  if (typeof direct === "number" && Number.isFinite(direct) && direct > 0) {
    return Math.max(0, direct);
  }
  const totalFallback = coerceNumber(
    order?.grandTotal ??
      order?.grand_total ??
      order?.total,
  );
  if (typeof totalFallback === "number" && Number.isFinite(totalFallback) && totalFallback > 0) {
    return Math.max(0, totalFallback);
  }
  return 0;
};

const resolveOrderSalesSubtotal = (order: any): number => {
  if (!order) return 0;
  const lineItems = Array.isArray(order?.lineItems)
    ? order.lineItems
    : Array.isArray(order?.items)
      ? toOrderLineItems(order.items)
      : [];

  const fromLines = Array.isArray(lineItems)
    ? lineItems.reduce((sum: number, line: any) => {
        const qty = coerceNumber(line?.quantity) ?? 0;
        if (qty <= 0) return sum;
        const lineTotal = coerceNumber(line?.total);
        if (typeof lineTotal === "number" && Number.isFinite(lineTotal) && lineTotal > 0) {
          return sum + lineTotal;
        }
        const unitPrice = coerceNumber(line?.price);
        if (typeof unitPrice === "number" && Number.isFinite(unitPrice) && unitPrice > 0) {
          return sum + unitPrice * qty;
        }
        return sum;
      }, 0)
    : 0;

  if (fromLines > 0) {
    return Math.max(0, fromLines);
  }

  const direct = coerceNumber(
    order?.itemsSubtotal ??
      order?.items_subtotal ??
      order?.itemsTotal ??
      order?.items_total ??
      order?.subtotal,
  );
  if (typeof direct === "number" && Number.isFinite(direct) && direct > 0) {
    return Math.max(0, direct);
  }

  return 0;
};

const resolveOrderSalesPricingMode = (order: any): "wholesale" | "retail" => {
  const pricingModeRaw =
    order?.pricingMode ??
    (order as any)?.pricing_mode ??
    (order as any)?.payload?.order?.pricingMode ??
    (order as any)?.payload?.order?.pricing_mode ??
    (order as any)?.order?.pricingMode ??
    (order as any)?.order?.pricing_mode ??
    (order as any)?.orders?.pricingMode ??
    (order as any)?.orders?.pricing_mode ??
    (order as any)?.pricing ??
    (order as any)?.priceType ??
    (order as any)?.orders?.pricing ??
    (order as any)?.orders?.priceType ??
    null;
  const pricingMode = String(pricingModeRaw || "").toLowerCase().trim();
  return pricingMode === "retail" ? "retail" : "wholesale";
};

const normalizeLeadTypeValue = (value: unknown) =>
  String(value || "")
    .trim()
    .toLowerCase()
    .replace(/[\s-]+/g, "_");

const isHouseLeadTypeValue = (value: unknown) => {
  const normalized = normalizeLeadTypeValue(value);
  return (
    normalized === "house" ||
    normalized === "contact_form" ||
    normalized === "house_contact"
  );
};

const isHouseContactProspectRow = (row: any) => {
  if (!row || typeof row !== "object") {
    return false;
  }
  const status = String(row?.status || "").trim().toLowerCase();
  const id = String(row?.id || "").trim().toLowerCase();
  const source = String(row?.source || "").trim().toLowerCase();
  const leadType = normalizeLeadTypeValue(row?.leadType || row?.lead_type);
  const referrerName = String(
    row?.referrerDoctorName || row?.referrer_doctor_name || "",
  )
    .trim()
    .toLowerCase();
  const contactFormIdRaw =
    row?.contactFormId ||
    row?.contact_form_id ||
    row?.contactFormID ||
    row?.contact_formId ||
    null;
  const hasContactFormId =
    (typeof contactFormIdRaw === "string" && contactFormIdRaw.trim().length > 0) ||
    (typeof contactFormIdRaw === "number" && Number.isFinite(contactFormIdRaw));
  const hasHouseReferrerName =
    referrerName === "contact form / house" ||
    referrerName === "house / contact form";

  return (
    status === "contact_form" ||
    id.startsWith("contact_form:") ||
    hasContactFormId ||
    source === "contact_form" ||
    source === "house" ||
    source === "house_contact" ||
    isHouseLeadTypeValue(leadType) ||
    hasHouseReferrerName
  );
};

const normalizeStringField = (value: unknown) => {
  if (typeof value === "string") {
    const trimmed = value.trim();
    return trimmed.length > 0 ? trimmed : null;
  }
  return null;
};

