function InlineEditableValueRow({
  label,
  value,
  type = "text",
  autoComplete,
  editable = false,
  startEditing = false,
  multiline = false,
  rows = 4,
  alignStart = false,
  displayValue,
  rowClassName,
  labelClassName,
  displayClassName,
  displayValueClassName,
  contentClassName,
  scrollableDisplay = false,
  editorClassName,
  onSave,
  onCancel,
}: {
  label: string;
  value: string;
  type?: string;
  autoComplete?: string;
  editable?: boolean;
  startEditing?: boolean;
  multiline?: boolean;
  rows?: number;
  alignStart?: boolean;
  displayValue?: ReactNode;
  rowClassName?: string;
  labelClassName?: string;
  displayClassName?: string;
  displayValueClassName?: string;
  contentClassName?: string;
  scrollableDisplay?: boolean;
  editorClassName?: string;
  onSave?: (next: string) => Promise<void> | void;
  onCancel?: () => void;
}) {
  const [editing, setEditing] = useState(false);
  const [next, setNext] = useState(value);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    setNext(value);
  }, [value]);

  useEffect(() => {
    if (!editable && editing) {
      setEditing(false);
    }
  }, [editable, editing]);

  useEffect(() => {
    if (editable && startEditing) {
      setEditing(true);
    }
  }, [editable, startEditing]);

  const saveValue = useCallback(async () => {
    if (!editable || !onSave || saving) {
      return;
    }
    setSaving(true);
    try {
      await onSave(next);
      setEditing(false);
    } catch {
      // Keep the row in edit mode when validation or save fails.
    } finally {
      setSaving(false);
    }
  }, [editable, next, onSave, saving]);

  if (scrollableDisplay) {
    return (
      <div
        className={clsx(
          "editable-row group flex w-max min-w-max gap-3",
          alignStart ? "items-start" : "items-center",
          rowClassName,
        )}
      >
        <div
          className={clsx(
            "min-w-[7rem] text-sm font-medium text-slate-700",
            alignStart ? "self-start pt-1" : "self-center",
            labelClassName,
          )}
        >
          {label}
        </div>
        <div
          className={clsx(
            "w-max min-w-max",
            alignStart ? "self-start" : "self-center",
            contentClassName,
          )}
        >
          {editing ? (
            multiline ? (
              <Textarea
                className={clsx(
                  "w-full min-h-[160px] squircle-sm border border-slate-200/70 bg-white/96 px-3 py-2 text-sm text-slate-900 focus:border-primary focus:outline-none focus:ring-2 focus:ring-primary/30 whitespace-pre-line",
                  editorClassName,
                )}
                value={next}
                autoComplete={autoComplete}
                rows={rows}
                onChange={(event) => setNext(event.currentTarget.value)}
              />
            ) : (
              <input
                className={clsx(
                  "min-w-[18rem] h-9 px-3 squircle-sm border border-slate-200/70 bg-white/96 text-sm focus:border-primary focus:outline-none focus:ring-2 focus:ring-primary/30",
                  editorClassName,
                )}
                value={next}
                type={type}
                autoComplete={autoComplete}
                onChange={(event) => setNext(event.currentTarget.value)}
                onKeyDown={async (event) => {
                  if (event.key === "Enter") {
                    event.preventDefault();
                    await saveValue();
                  }
                }}
              />
            )
          ) : (
            <div
              className={clsx(
                "w-max min-w-max",
                displayClassName,
              )}
            >
              <div
                className={clsx(
                  "inline-flex min-w-max items-center gap-2 text-sm text-slate-700 whitespace-nowrap",
                  alignStart ? "items-start" : "items-center",
                )}
              >
                <span
                  className={clsx(
                    "min-w-max whitespace-nowrap break-normal",
                    displayValueClassName,
                  )}
                >
                  {displayValue ?? (value || "—")}
                </span>
                {editable && onSave ? (
                  <button
                    type="button"
                    className={clsx("inline-edit-button", editing && "is-active")}
                    onClick={() => setEditing(true)}
                    aria-label={`Edit ${label}`}
                    title={`Edit ${label}`}
                  >
                    <Pencil className="w-3 h-3" />
                  </button>
                ) : null}
              </div>
            </div>
          )}
          {editing ? (
            <div className="mt-2 flex items-center gap-2">
              <Button
                variant="outline"
                className="squircle-sm"
                disabled={saving}
                onClick={() => void saveValue()}
              >
                {saving ? "Saving…" : "Save"}
              </Button>
              <Button
                variant="ghost"
                className="squircle-sm"
                onClick={() => {
                  setNext(value);
                  setEditing(false);
                  onCancel?.();
                }}
              >
                Cancel
              </Button>
            </div>
          ) : null}
        </div>
      </div>
    );
  }

  return (
    <div
      className={clsx(
        "editable-row group flex gap-3",
        alignStart ? "items-start" : "items-center",
        rowClassName,
      )}
    >
      <div
        className={clsx(
          "min-w-[7rem] text-sm font-medium text-slate-700",
          alignStart ? "self-start pt-1" : "self-center",
          labelClassName,
        )}
      >
        {label}
      </div>
      <div
        className={clsx(
          "flex-1 flex gap-2 flex-wrap",
          alignStart ? "items-start" : "items-center",
          contentClassName,
        )}
      >
        {editing ? (
          multiline ? (
            <Textarea
              className={clsx(
                "w-full min-h-[160px] squircle-sm border border-slate-200/70 bg-white/96 px-3 py-2 text-sm text-slate-900 focus:border-primary focus:outline-none focus:ring-2 focus:ring-primary/30 whitespace-pre-line",
                editorClassName,
              )}
              value={next}
              autoComplete={autoComplete}
              rows={rows}
              onChange={(event) => setNext(event.currentTarget.value)}
            />
          ) : (
            <input
              className={clsx(
                "w-full h-9 px-3 squircle-sm border border-slate-200/70 bg-white/96 text-sm focus:border-primary focus:outline-none focus:ring-2 focus:ring-primary/30",
                editorClassName,
              )}
              value={next}
              type={type}
              autoComplete={autoComplete}
              onChange={(event) => setNext(event.currentTarget.value)}
              onKeyDown={async (event) => {
                if (event.key === "Enter") {
                  event.preventDefault();
                  await saveValue();
                }
              }}
            />
          )
        ) : (
          scrollableDisplay ? (
            <div
              className={clsx(
                "min-w-0 overflow-x-auto no-scrollbar",
                displayClassName,
              )}
            >
              <div
                className={clsx(
                  "text-sm text-slate-700 flex min-w-max gap-2",
                  alignStart ? "items-start" : "items-center",
                )}
              >
                <span
                  className={clsx(
                    "min-w-max whitespace-nowrap break-normal",
                    displayValueClassName,
                  )}
                >
                  {displayValue ?? (value || "—")}
                </span>
                {editable && onSave ? (
                  <button
                    type="button"
                    className={clsx("inline-edit-button", editing && "is-active")}
                    onClick={() => setEditing(true)}
                    aria-label={`Edit ${label}`}
                    title={`Edit ${label}`}
                  >
                    <Pencil className="w-3 h-3" />
                  </button>
                ) : null}
              </div>
            </div>
          ) : (
            <div
              className={clsx(
                "text-sm text-slate-700 flex gap-2 min-w-0 flex-wrap",
                alignStart ? "items-start" : "items-center",
                displayClassName,
              )}
            >
              <span
                className={clsx("min-w-0 break-all", displayValueClassName)}
              >
                {displayValue ?? (value || "—")}
              </span>
              {editable && onSave ? (
                <button
                  type="button"
                  className={clsx("inline-edit-button", editing && "is-active")}
                  onClick={() => setEditing(true)}
                  aria-label={`Edit ${label}`}
                  title={`Edit ${label}`}
                >
                  <Pencil className="w-3 h-3" />
                </button>
              ) : null}
            </div>
          )
        )}
        {editing ? (
          <div className="flex items-center gap-2">
            <Button
              variant="outline"
              className="squircle-sm"
              disabled={saving}
              onClick={() => void saveValue()}
            >
              {saving ? "Saving…" : "Save"}
            </Button>
            <Button
              variant="ghost"
              className="squircle-sm"
              onClick={() => {
                setNext(value);
                setEditing(false);
                onCancel?.();
              }}
            >
              Cancel
            </Button>
          </div>
        ) : null}
      </div>
    </div>
  );
}

export default function App() {
  const pathname =
    typeof window !== "undefined"
      ? normalizePathname(window.location.pathname)
      : "/";
  if (isPublicSitePath(pathname)) {
    return <PublicSite pathname={pathname} />;
  }
  return <MainApp />;
}
